    .mode = i2s_mode_rx, // I2S_RX
    .sample_rate = 44100,
    .bits_per_sample = i2s_bits_per_sample_16bit,
    .channel_format = i2s_channel_format_all_left,
    .communication_format = i2s_comm_format_i2s,
    .intr_alloc_flags = 0,
    .dma_buf_count = 2,
    .dma_buf_len = 1024,
    .use_apll = 0
};
```
3. Then, define the WAV header structure:
```c
typedef struct {
    char riff[4];
    uint32_t fileSize;
    char wave[4];
    char fmt[4];
    uint32_t fmtSize;
    uint16_t format;
    uint16_t numChannels;
    uint32_t sampleRate;
    uint32_t byteRate;
    uint16_t blockAlign;
    uint16_t bitsPerSample;
    char data[4];
    uint32_t dataSize;
} WavHeader;
```
4. Create a function to encode the audio data in WAV format:
```c
void encodeWav(uint16_t* audioData, uint32_t dataSize) {
    WavHeader header;
    header.riff[0] = 'R';
    header.riff[1] = 'I';
    header.riff[2] = 'F';
    header.riff[3] = 'F';
    header.fileSize = dataSize + 36;
    header.wave[0] = 'W';
    header.wave[1] = 'A';
    header.wave[2] = 'V';
    header.wave[3] = 'E';
    header.fmt[0] = 'f';
    header.fmt[1] = 'm';
    header.fmt[2] = 't';
    header.fmt[3] = ' ';
    header.fmtSize = 16;
    header.format = 1;
    header.numChannels = 1;
    header.sampleRate = 44100;
    header.byteRate = 88200;
    header.blockAlign = 2;
    header.bitsPerSample = 16;
    header.data[0] = 'd';
    header.data[1] = 'a';
    header.data[2] = 't';
    header.data[3] = 'a';
    header.dataSize = dataSize;

    // Send the WAV header
    Serial.write((char*)&header, 44);

    // Send the audio data
    Serial.write((char*)audioData, dataSize);
}
```
5. Finally, call the `encodeWav` function in your main loop to encode the audio data:
```c
void loop() {
    // Read audio data from the INMP441 digital mic
    uint16_t audioData[1024];
    i2s_read(I2S_NUM_0, audioData, 1024, 100);

    // Encode the audio data in WAV format
    encodeWav(audioData, 1024);
}
```
